import{_ as t,o as a,c as r,ag as s}from"./chunks/framework.CAXxHpAX.js";const o="/screenshots/test-case-detail.png",p=JSON.parse('{"title":"UI overview","description":"","frontmatter":{"title":"UI overview","lang":"en-US"},"headers":[],"relativePath":"ui-overview.md","filePath":"ui-overview.md","lastUpdated":1783771786000}'),n={name:"ui-overview.md"};function i(d,e,l,c,h,u){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="ui-overview" tabindex="-1">UI overview <a class="header-anchor" href="#ui-overview" aria-label="Permalink to &quot;UI overview&quot;">​</a></h1><p>This page is a <strong>map of the dashboard</strong> — where each view lives and what it&#39;s for. For the concepts behind a feature, follow the links to the dedicated pages (<a href="./flaky-tests.html">Flaky tests &amp; analytics</a>, <a href="./ai-diagnosis.html">AI diagnosis &amp; clustering</a>, <a href="./reporter.html">Reporter</a>).</p><p>The dashboard is a single-page app built with <a href="https://ui.nuxt.com" target="_blank" rel="noreferrer">Nuxt UI</a>. It updates itself in real time over Server-Sent Events — pages refresh automatically when runs start or finish, so you never reload manually.</p><h2 id="inline-help" tabindex="-1">Inline help <a class="header-anchor" href="#inline-help" aria-label="Permalink to &quot;Inline help&quot;">​</a></h2><p>Blocks that aren&#39;t self-explanatory carry a small muted help icon (a circled question mark) next to their title. Click it for a short explanation and, where relevant, a <strong>Learn more</strong> link into these docs. The icon is keyboard-focusable and closes with <code>Esc</code>. Self-explanatory blocks (counters, search boxes) have no icon, keeping the UI uncluttered.</p><h2 id="navigation" tabindex="-1">Navigation <a class="header-anchor" href="#navigation" aria-label="Permalink to &quot;Navigation&quot;">​</a></h2><p>The sidebar gives access to the top-level sections:</p><table tabindex="0"><thead><tr><th>Section</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td>Home</td><td><code>/</code></td><td>Aggregate stats and activity across all projects</td></tr><tr><td>Projects</td><td><code>/projects</code></td><td>Full project listing with search and tag filters</td></tr><tr><td>Settings</td><td><code>/settings</code></td><td>Configuration — general, account, users, storage, tags, wasted time, AI, notifications</td></tr><tr><td>API docs</td><td><code>/docs</code></td><td>Interactive OpenAPI 3.1 reference (Scalar) — browse schemas and run live requests</td></tr><tr><td>MCP server</td><td><code>/mcp</code></td><td>Setup guide for connecting AI clients (see <a href="./mcp.html">MCP server</a>)</td></tr></tbody></table><p>Everything else is reached by drilling into a project, run, or test case:</p><table tabindex="0"><thead><tr><th>Page</th><th>Path</th></tr></thead><tbody><tr><td>Project detail</td><td><code>/projects/:id</code></td></tr><tr><td>Project edit</td><td><code>/projects/:id/edit</code></td></tr><tr><td>Test cases (project)</td><td><code>/projects/:id/test-cases</code></td></tr><tr><td>Failure cluster</td><td><code>/failure-clusters/:id</code></td></tr><tr><td>Test run</td><td><code>/test-runs/:id</code></td></tr><tr><td>Test case</td><td><code>/test-cases/:id</code></td></tr></tbody></table><h2 id="home" tabindex="-1">Home <a class="header-anchor" href="#home" aria-label="Permalink to &quot;Home&quot;">​</a></h2><p>A quick health check across all projects: <strong>stats cards</strong> (projects, runs, active/passing projects, flaky count, slowest project), a <strong>test-results trend chart</strong> (pass/fail/skip/flaky over time), <strong>recent projects</strong>, and a getting-started snippet for teams that haven&#39;t wired up the reporter yet.</p><h2 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h2><p>The primary hub: instant <strong>text search</strong>, <strong>tag filters</strong>, and a table showing each project&#39;s run count, last-run date, duration, status, test pass/fail bar, report links, and actions. Create a project manually with <strong>New project</strong> (it&#39;s also created automatically on first result submission).</p><h2 id="project-detail" tabindex="-1">Project detail <a class="header-anchor" href="#project-detail" aria-label="Permalink to &quot;Project detail&quot;">​</a></h2><p>The complete history for one project, organized into tabs:</p><ul><li><strong>Test runs</strong> — every run with status, start time, duration, test counts, and browser badges; select two runs to compare. Runs with a shared failure signature roll up into <strong>Failure clusters</strong> here (see <a href="./ai-diagnosis.html">AI diagnosis &amp; clustering</a>).</li><li><strong>Flaky tests</strong> — intermittent tests scored by a composite flakiness metric, with root-cause classification and impact ranking. See <a href="./flaky-tests.html#flaky-test-detection">Flaky tests &amp; analytics</a>.</li><li><strong>Performance</strong> — average/P90 duration trends and a slowest-tests table. See <a href="./flaky-tests.html#performance">Performance</a>.</li><li><strong>Test cases</strong> — every unique test with pass rate, result breakdown, average duration, and last-run date.</li><li><strong>Compare</strong> — side-by-side delta between two runs (new failures, recovered, duration changes).</li><li><strong>Spec health</strong> — a heatmap grouping test cases by spec file and coloring each by pass rate, so an unhealthy area of the suite jumps out. See <a href="./flaky-tests.html#spec-health-heatmap">Spec health heatmap</a>.</li><li><strong>Members</strong> <em>(admins, when auth is enabled)</em> — grant or scope project access per user. See <a href="./authentication.html#project-access">Project access</a>.</li></ul><p>Project <strong>edit</strong> (<code>/projects/:id/edit</code>) sets the label, description, tags, per-project SCM token, and <strong>AI diagnosis instructions</strong> (project-specific context combined with the global instructions for every diagnosis).</p><h2 id="test-run-detail" tabindex="-1">Test run detail <a class="header-anchor" href="#test-run-detail" aria-label="Permalink to &quot;Test run detail&quot;">​</a></h2><p>A deep dive into a single run. The <strong>summary header</strong> shows status, duration, test counts, duration metrics (avg/P90), and metadata cards (CI/environment, source control, tags). While a run is still <code>running</code>, a <strong>live progress bar</strong> and streaming results appear in real time. <strong>Reports</strong> buttons open or download the attached HTML reports (Playwright, Monocart).</p><p>The right panel is tabbed:</p><ul><li><strong>Test cases</strong> — every test with browser icon, status, duration, location, errors, annotations, and traces; searchable, filterable by status/browser, and grouped by suite hierarchy (describe blocks).</li><li><strong>Insights</strong> — what changed versus the last passing baseline: new regressions, recurring failures, fixed tests, new flaky tests, performance changes, worker imbalance, and new clusters. See <a href="./flaky-tests.html#run-insights">Run insights</a>.</li><li><strong>Failure groups</strong> — failures grouped by error fingerprint, each with flaky/worker-correlation signals and actions to filter the list, trigger AI diagnosis, or open the cluster. See <a href="./ai-diagnosis.html">AI diagnosis &amp; clustering</a>.</li><li><strong>Regression</strong> <em>(shown when a baseline exists)</em> — the regression delta for this run at a glance.</li><li><strong>Timeline</strong> — a horizontal per-worker timeline of test execution, with a span-type filter to isolate test phases (setup, actual test, wasted waits, teardown); click a bar to jump to that test case.</li><li><strong>Compare</strong> — pick a baseline run for a side-by-side delta (improved / regressed / unchanged).</li><li><strong>Slow endpoints</strong> — network requests grouped by method + normalized route, with avg/p90/max duration and error rate. Requires the <a href="./capture-fixtures.html">capture fixtures</a>.</li></ul><p>Administrators can <strong>delete</strong> the entire run and its files from the header.</p><h2 id="test-case-detail" tabindex="-1">Test case detail <a class="header-anchor" href="#test-case-detail" aria-label="Permalink to &quot;Test case detail&quot;">​</a></h2><p>Everything about a single test execution: a <strong>status card</strong> (id, title, copyable location, duration, worker, retries, slowest step, duration-vs-average), <strong>run context</strong> (environment, CI, branch, commit, author, browser), a link into the specific test in the HTML report, and attached <strong>traces</strong> (open in the Playwright viewer or download; they stream in live while the parent run is in progress).</p><p>For a failed test the page opens on the <strong>Failure</strong> tab, which leads with the raw <strong>error</strong> (copyable), then — when the failure belongs to a cluster — a banner linking to the <a href="#failure-cluster-detail">failure cluster</a> where the full investigation lives (cross-test evidence, what changed since the last green run, and AI diagnosis); below that, <strong>alternative locators</strong> when a locator broke, with ranked replacements and a recommended fix (see <a href="./reporter.html#locator-healing">locator healing</a>), and the failure-time <strong>ARIA snapshot</strong>. The other tabs cover <strong>performance hints</strong>, execution <strong>steps</strong>, <strong>Web Vitals</strong> with color-coded thresholds, <strong>network requests</strong> with inline backend server logs (see <a href="./backend-logs.html">Backend logs</a>), and a <strong>history</strong> chart of this test&#39;s status and duration over time. The Web Vitals, network, console, ARIA-snapshot, and alternative-locators data all come from the <a href="./capture-fixtures.html">capture fixtures</a>.</p><figure><img src="'+o+'" alt="Test case detail page with summary stats, duration trend, status history, and recent executions"><figcaption>The test case detail page — pass rate and duration stats, a duration trend, a status-history strip, and every recent execution of this one test.</figcaption></figure><h2 id="trace-viewer" tabindex="-1">Trace viewer <a class="header-anchor" href="#trace-viewer" aria-label="Permalink to &quot;Trace viewer&quot;">​</a></h2><p>Every trace shows a <strong>View trace</strong> button that opens the full Playwright trace viewer — the same UI as <code>npx playwright show-trace</code>, with the DOM snapshot timeline, action log, network, console, and source.</p><p>The viewer is <strong>served by the dashboard itself</strong> (the <code>playwright-core</code> viewer assets are bundled and served at <code>/trace-viewer/</code>), so traces are never uploaded to a third party — unlike sending a colleague to <code>trace.playwright.dev</code>, the bytes stay on your server. Traces are stored efficiently: each archive is split into a slim events ZIP plus a project-wide, hash-deduplicated resource pool, and reconstructed on download (see <a href="./storage.html">Storage</a>). Trace blobs are content-addressed, so the browser caches them and re-opening a trace is instant.</p><div class="tip custom-block"><p class="custom-block-title">Authentication caveat</p><p>The bundled <code>/trace-viewer/</code> is same-origin, so it works whether or not <a href="./authentication.html">authentication</a> is enabled. The hosted <code>trace.playwright.dev</code> viewer is a different origin and cannot send your session cookie, so it only works against a dashboard with auth disabled — use the built-in <strong>View trace</strong> button, which always works.</p></div><h2 id="failure-cluster-detail" tabindex="-1">Failure cluster detail <a class="header-anchor" href="#failure-cluster-detail" aria-label="Permalink to &quot;Failure cluster detail&quot;">​</a></h2><p>Each cluster (<code>/failure-clusters/:id</code>) opens on a summary — signature, affected tests, and <strong>Triage</strong> (set status open/resolved/ignored and write a note) — above a two-column body. The left column collapses each investigation section to a header with an at-a-glance peek (click to expand, and the state is remembered): the raw <strong>error message</strong>, an <strong>alternative-locators</strong> panel for broken locators, <strong>test evidence</strong> (one tab per affected case, each linking through to its test-run case, with screenshots, traces, failing steps, console/network signals and source), and <strong>what changed</strong> (the SCM diff since the last green run, with a baseline-commit picker and commit browser). The right column holds the <strong>AI diagnosis</strong> — an SCM-grounded LLM analysis whose cited evidence links back to the matching left-column section. Full detail: <a href="./ai-diagnosis.html">AI diagnosis &amp; clustering</a>.</p><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Page</th><th>Path</th><th>What it does</th></tr></thead><tbody><tr><td>General</td><td><code>/settings</code></td><td>Basic app configuration; a <strong>Reset Demo</strong> button in demo mode</td></tr><tr><td>Account</td><td><code>/settings/account</code></td><td>Your display name, email, password, and <strong>connected accounts</strong> (link/unlink Google or GitHub — see <a href="./authentication.html#oauth-google-github">OAuth</a>)</td></tr><tr><td>Users</td><td><code>/settings/users</code></td><td>User accounts, roles, project access, and API keys (shown once, stored hashed) — see <a href="./authentication.html">Authentication</a></td></tr><tr><td>Storage</td><td><code>/settings/storage</code></td><td>Storage stats and cleanup (bulk-delete runs older than N days) — see <a href="./storage.html#storage-management">Storage</a></td></tr><tr><td>Tags</td><td><code>/settings/tags</code></td><td>Create, color, edit, and delete the tags used to organize projects</td></tr><tr><td>Wasted time</td><td><code>/settings/wasted-time</code></td><td>Patterns that classify which Playwright waits count as &quot;wasted time&quot; on the timeline — see <a href="./configuration.html#wasted-time">Configuration</a></td></tr><tr><td>AI</td><td><code>/settings/ai</code></td><td>Provider/model roles, auto-diagnose, global instructions, and context limits — see <a href="./ai-diagnosis.html#enabling-ai-diagnosis">AI diagnosis</a></td></tr><tr><td>Notifications</td><td><code>/settings/notifications</code></td><td>Channels, subscriptions, and SMTP — see <a href="./notifications.html">Notifications &amp; alerts</a></td></tr></tbody></table><p>Where an environment variable backs a setting, the field is shown read-only with a lock badge and the env var name (see <a href="./configuration.html">Configuration</a>).</p><h2 id="real-time-updates" tabindex="-1">Real-time updates <a class="header-anchor" href="#real-time-updates" aria-label="Permalink to &quot;Real-time updates&quot;">​</a></h2><p>The dashboard uses Server-Sent Events so it never needs a manual refresh:</p><ul><li><strong>Global stream</strong> (<code>/api/stream</code>) — tells every connected client when a run starts, finishes, or is submitted; pages re-fetch their data.</li><li><strong>Per-run stream</strong> (<code>/api/test-runs/:id/stream</code>) — drives the live progress on the run detail page during a streaming run.</li></ul><h2 id="live-demo" tabindex="-1">Live demo <a class="header-anchor" href="#live-demo" aria-label="Permalink to &quot;Live demo&quot;">​</a></h2><p>The <a href="https://piwitests.github.io/demo/" target="_blank" rel="noreferrer">live demo</a> runs entirely in your browser (in-memory SQLite) and adds two things the real app doesn&#39;t need:</p><p><strong>Simulate a test run</strong> — the demo banner replays the exact streaming protocol a Piwi reporter speaks during a real run, so you can watch one arrive live. Scenarios: a passing run, a run with failures (joining a known cluster plus a brand-new one), flaky retries, a performance regression, an interrupted run, and a cross-browser run. Each creates a real run in the in-browser database, so worker timeline, failure groups, and history comparisons all behave exactly as they would against a server.</p><p><strong>Acting as</strong> — the demo runs with authentication conceptually enabled. Switch between pre-seeded identities (an admin, a CI reporter, and several project-scoped users) to see how <a href="./authentication.html#project-access">project access</a> changes what each user sees. Acting as the admin, you can change affectations live and then switch users to see the effect.</p><h2 id="responsive-dark-mode" tabindex="-1">Responsive &amp; dark mode <a class="header-anchor" href="#responsive-dark-mode" aria-label="Permalink to &quot;Responsive &amp; dark mode&quot;">​</a></h2><p>The dashboard is fully responsive — sidebar navigation on desktop, collapsible sidebar and horizontally scrolling tables on tablet, and a stacked/hamburger layout on mobile. It supports light and dark themes, following the system preference by default, with a manual toggle in the sidebar.</p>',45)])])}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
